import { CHART_DOMAIN_HELPERS } from '../../../../brush/chart-helpers/domain-helpers';

/**
 *
 * @param instanceMap
 * @param selectionManager
 */
export function filterChart_C(instanceMap, selectionManager) {
    let eventManager = this,
        chart = eventManager.chart;

    chart.zooming = true;

    let domainInfo = selectionManager.point;

    chart.disableAnimation = true;

    if (domainInfo.x && domainInfo.x[0].domain) {
        chart.viewPortExtent = domainInfo.x && domainInfo.x[0].domain;
    }

    CHART_DOMAIN_HELPERS.FILTER_CHART(domainInfo, chart);
}
